27	/// QIR output schema
28	enum struct RecordSchemaType { LABELED, ORDERED };
29	enum struct RecordType { HEADER, METADATA, OUTPUT, START, END };
30	enum struct OutputType { RESULT, BOOL, INT, DOUBLE };
31	enum struct ContainerType { NONE, ARRAY, TUPLE };
32	
33	namespace detail {
34	
35	template <typename T>
36	T parseInteger(const std::string &value) {
37	  static_assert(std::is_integral_v<T> && !std::is_same_v<T, bool>);
38	  if (value.empty())
39	    throw std::runtime_error("Invalid integer value");
40	
41	  std::string_view input(value);
42	  if (input.front() == '+') {
43	    input.remove_prefix(1);
44	    if (input.empty() || input.front() == '+' || input.front() == '-')
45	      throw std::runtime_error("Invalid integer value");
46	  }
47	
48	  std::int64_t parsed = 0;
49	  const auto [end, error] =
50	      std::from_chars(input.data(), input.data() + input.size(), parsed);
51	  if (error != std::errc{} || end != input.data() + input.size() ||
52	      parsed < static_cast<std::int64_t>(std::numeric_limits<T>::min()) ||
53	      parsed > static_cast<std::int64_t>(std::numeric_limits<T>::max()))
54	    throw std::runtime_error("Invalid integer value");
55	  return static_cast<T>(parsed);
56	}
57	
58	inline std::size_t parseSize(std::string_view value) {
59	  if (value.empty())
60	    throw std::runtime_error("Invalid size value");
61	
62	  std::size_t parsed = 0;
63	  const auto [end, error] =
64	      std::from_chars(value.data(), value.data() + value.size(), parsed);
65	  if (error != std::errc{} || end != value.data() + value.size())
66	    throw std::runtime_error("Invalid size value");
67	  return parsed;
68	}
