70	//===----------------------------------------------------------------------===//
71	// Type conversion infrastructure for string-to-value parsing
72	//===----------------------------------------------------------------------===//
73	
74	/// Abstract base class for string to specific datatype conversion
75	template <typename T>
76	class TypeConverterBase {
77	public:
78	  virtual ~TypeConverterBase() = default;
79	  virtual T convert(const std::string &value) const = 0;
80	};
81	
82	class BooleanConverter : public TypeConverterBase<bool> {
83	public:
84	  bool convert(const std::string &value) const override {
85	    if (value == "true" || value == "True" || value == "1")
86	      return true;
87	    if (value == "false" || value == "False" || value == "0")
88	      return false;
89	    throw std::runtime_error("Invalid boolean value");
90	  }
91	};
92	
93	template <typename T>
94	class IntegerConverter : public TypeConverterBase<T> {
95	public:
96	  T convert(const std::string &value) const override {
97	    return parseInteger<T>(value);
98	  }
99	};
100	
101	template <typename T>
102	class FloatConverter : public TypeConverterBase<T> {
103	public:
104	  T convert(const std::string &value) const override {
105	    // The `<charconv>` float overloads are annotated as introduced in
106	    // macOS 26.0 and are unavailable at CUDA-Q's macOS 13.0 deployment
107	    // target. Use `std::stof`/`std::stod` and enforce the same
108	    // "full-token, no leading whitespace" grammar via an explicit
109	    // length check and an `isspace` prefix guard. `stof`/`stod` accept
110	    // `inf`/`infinity`/`nan` case-insensitively; those non-finite
111	    // spellings are the runtime's own output (see the `ostringstream`
112	    // emitter) and must round-trip.
113	    if (value.empty() ||
114	        std::isspace(static_cast<unsigned char>(value.front())))
115	      throw std::runtime_error("Invalid floating-point value");
116	
117	    try {
118	      std::size_t parsedLength = 0;
119	      T parsed{};
120	      if constexpr (std::is_same_v<T, float>)
121	        parsed = std::stof(value, &parsedLength);
122	      else
123	        parsed = std::stod(value, &parsedLength);
124	      if (parsedLength != value.size())
125	        throw std::runtime_error("Invalid floating-point value");
126	      return parsed;
127	    } catch (const std::logic_error &) {
128	      // `std::invalid_argument` (no conversion) and `std::out_of_range`
129	      // (overflow/underflow) both derive from `std::logic_error`; the
130	      // record grammar treats them identically.
131	      throw std::runtime_error("Invalid floating-point value");
132	    }
133	  }
134	};
135	
136	//===----------------------------------------------------------------------===//
137	// Buffer management for storing decoded data
138	//===----------------------------------------------------------------------===//
139	
140	/// A helper class to manage the underlying memory buffer used by
141	/// 'RecordLogParser'. For container types, i.e. composite records, the buffer
142	/// acts as outer vector with pointers to inner buffers.
143	class BufferHandler {
144	public:
145	  BufferHandler() = default;
146	  ~BufferHandler() = default;
147	  /// Copying and assignment not permitted
148	  BufferHandler(BufferHandler &other) = delete;
149	  BufferHandler &operator=(BufferHandler &other) = delete;
150	  BufferHandler(const BufferHandler &) = delete;
151	  BufferHandler &operator=(const BufferHandler &) = delete;
152	  BufferHandler(BufferHandler &&) = default;
153	  BufferHandler &operator=(BufferHandler &&) = default;
154	
155	  void *getBufferPtr() const {
156	    return reinterpret_cast<void *>(const_cast<char *>(buffer.data()));
157	  }
158	
159	  std::size_t getBufferSize() const { return buffer.size(); }
160	
161	  void resizeBuffer(std::size_t more) { buffer.resize(buffer.size() + more); }
162	
163	  template <typename T>
164	  void addPrimitiveRecord(T value) {
165	    std::size_t position = buffer.size();
166	    buffer.resize(position + sizeof(T));
167	    std::memcpy(buffer.data() + position, &value, sizeof(T));
168	  }
169	
170	  template <typename T>
171	  size_t allocateArrayRecord(size_t arrSize) {
172	    size_t vectorOffset = buffer.size();
173	    if constexpr (std::is_same_v<T, bool>) {
174	      auto *allocation = new std::vector<bool>(arrSize);
175	      if (!allocation)
176	        throw std::runtime_error("Memory allocation failed");
177	      auto byteLength = sizeof(*allocation);
178	      buffer.resize(vectorOffset + byteLength);
179	      std::memcpy(buffer.data() + vectorOffset, allocation, byteLength);
180	      return vectorOffset;
181	    }
182	
183	    buffer.resize(vectorOffset + 3 * sizeof(T *));
184	    size_t byteLength = arrSize * sizeof(T);
185	    T *innerBuffer = static_cast<T *>(malloc(byteLength));
186	    if (!innerBuffer)
187	      throw std::runtime_error("Memory allocation failed");
188	    std::memset(innerBuffer, 0, byteLength);
189	    /// Initialize the three pointers of the inner vector
190	    T *startPtr = innerBuffer;
191	    T *end0Ptr = innerBuffer + arrSize;
192	    T *end1Ptr = end0Ptr;
193	    /// Store the pointers into the outer vector (buffer) without assuming the
194	    /// byte offset is suitably aligned for a T** access.
195	    T *pointers[] = {startPtr, end0Ptr, end1Ptr};
196	    std::memcpy(buffer.data() + vectorOffset, pointers, sizeof(pointers));
197	    return vectorOffset;
198	  }
199	
200	  template <typename T>
201	  void insertIntoArray(size_t offset, std::size_t index, T value) {
202	    if constexpr (std::is_same_v<T, bool>) {
203	      auto *v = reinterpret_cast<std::vector<bool> *>(buffer.data() + offset);
204	      (*v)[index] = value;
205	    } else {
206	      T *innerBuffer = nullptr;
207	      std::memcpy(&innerBuffer, buffer.data() + offset, sizeof(innerBuffer));
208	      innerBuffer[index] = value;
209	    }
210	  }
211	
212	  /// NOTE: This is used only if data layout (alignment) is missing
213	  template <typename T>
214	  size_t allocateTupleRecord() {
215	    size_t position = buffer.size();
216	    buffer.resize(position + sizeof(T));
217	    return position;
218	  }
219	
220	  template <typename T>
221	  void insertIntoTuple(size_t offset, T value) {
222	    if (offset > buffer.size() || sizeof(T) > buffer.size() - offset)
223	      throw std::runtime_error("Tuple element exceeds result buffer");
224	    std::memcpy(buffer.data() + offset, &value, sizeof(T));
225	  }
226	
227	private:
228	  std::vector<char> buffer;
229	};
