231	//===----------------------------------------------------------------------===//
232	// Container metadata tracking for composite / aggregate types
233	//===----------------------------------------------------------------------===//
234	
235	/// A helper structure to hold the current state of the container being
236	/// processed.
237	/// TODO: Handle nested containers.
238	class ContainerMetadata {
239	public:
240	  ContainerMetadata() = default;
241	
242	  void reset() {
243	    m_type = ContainerType::NONE;
244	    elementCount = 0;
245	    processedElements = 0;
246	    arrayType.clear();
247	    dataOffset = 0;
248	    tupleTypes.clear();
249	    tupleOffsets.clear();
250	  }
251	
252	  /// Parse string like "array<i32 x 4>"
253	  void extractArrayInfo(const std::string &label) {
254	    auto isArray = label.find("array");
255	    auto lessThan = label.find('<');
256	    auto greaterThan = label.find('>');
257	    auto x = label.find('x');
258	    if ((isArray == std::string::npos) || (lessThan == std::string::npos) ||
259	        (greaterThan == std::string::npos) || (x == std::string::npos))
260	      throw std::runtime_error("Array label missing keyword");
261	    if (elementCount !=
262	        parseSize(std::string_view(label).substr(x + 2, greaterThan - x - 2)))
263	      throw std::runtime_error("Array size mismatch in value and label.");
264	    arrayType = label.substr(lessThan + 1, x - lessThan - 2);
265	  }
266	
267	  /// Parse string like "tuple<i32, f64>"
268	  void extractTupleInfo(const std::string &label) {
269	    auto isTuple = label.find("tuple");
270	    auto lessThan = label.find('<');
271	    auto greaterThan = label.find('>');
272	    if ((isTuple == std::string::npos) || (lessThan == std::string::npos) ||
273	        (greaterThan == std::string::npos))
274	      throw std::runtime_error("Invalid tuple label");
275	    std::string types = label.substr(lessThan + 1, greaterThan - lessThan - 1);
276	    tupleTypes = cudaq::split(types, ',');
277	    if (elementCount != tupleTypes.size())
278	      throw std::runtime_error("Tuple size mismatch in value and label.");
279	    for (auto &ty : tupleTypes)
280	      ty.erase(std::remove(ty.begin(), ty.end(), ' '), ty.end());
281	  }
282	
283	  /// Parse string like "[0]" for array index, and ".0" for tuple index.
284	  std::size_t extractIndex(const std::string &label) {
285	    std::string_view index;
286	    if (label.size() >= 3 && label.front() == '[' && label.back() == ']')
287	      index = std::string_view(label).substr(1, label.size() - 2);
288	    else if (label.size() >= 2 && label.front() == '.')
289	      index = std::string_view(label).substr(1);
290	    else
291	      throw std::runtime_error("Index not found in label");
292	
293	    std::size_t value = 0;
294	    const auto [end, error] =
295	        std::from_chars(index.data(), index.data() + index.size(), value);
296	    if (error != std::errc{} || end != index.data() + index.size())
297	      throw std::runtime_error("Invalid index in label");
298	    return value;
299	  }
300	
301	  ContainerType m_type = ContainerType::ARRAY;
302	  std::size_t elementCount = 0;
303	  std::size_t processedElements = 0;
304	  std::size_t dataOffset = 0;
305	  std::string arrayType;
306	  std::vector<std::string> tupleTypes;
307	  std::vector<std::size_t> tupleOffsets;
308	};
309	
310	//===----------------------------------------------------------------------===//
311	// Type-specific data processing
312	//===----------------------------------------------------------------------===//
313	
314	/// Abstract base class for data handling depending on the type of the data
315	class DataHandlerBase {
316	public:
317	  virtual ~DataHandlerBase() = default;
318	  virtual void addRecord(BufferHandler &bh, const std::string &value) = 0;
319	  virtual size_t allocateArray(BufferHandler &bh, std::size_t arrSize) = 0;
320	  virtual void insertIntoArray(BufferHandler &bh, std::size_t offset,
321	                               std::size_t index, const std::string &value) = 0;
322	  virtual size_t allocateTuple(BufferHandler &bh) = 0;
323	  virtual void insertIntoTuple(BufferHandler &bh, std::size_t offset,
324	                               const std::string &value) = 0;
325	};
326	
327	template <typename T>
328	class DataHandler : public DataHandlerBase {
329	private:
330	  std::unique_ptr<detail::TypeConverterBase<T>> converter;
331	
332	public:
333	  DataHandler(std::unique_ptr<detail::TypeConverterBase<T>> conv)
334	      : converter(std::move(conv)) {}
335	  void addRecord(BufferHandler &bh, const std::string &value) override {
336	    bh.addPrimitiveRecord<T>(converter->convert(value));
337	  }
338	  size_t allocateArray(BufferHandler &bh, std::size_t arrSize) override {
339	    return bh.allocateArrayRecord<T>(arrSize);
340	  }
341	  void insertIntoArray(BufferHandler &bh, std::size_t offset, std::size_t index,
342	                       const std::string &value) override {
343	    bh.insertIntoArray<T>(offset, index, converter->convert(value));
344	  }
345	  size_t allocateTuple(BufferHandler &bh) override {
346	    return bh.allocateTupleRecord<T>();
347	  }
348	  void insertIntoTuple(BufferHandler &bh, std::size_t offset,
349	                       const std::string &value) override {
350	    bh.insertIntoTuple<T>(offset, converter->convert(value));
351	  }
352	};
353	
354	} // namespace detail
355	
356	namespace {
357	// Simplify look up of the required number of results by using a common
358	// identifier instead of different QIR versions (0.1 and 1.0)
359	constexpr char ResultCountMetadataName[] = "required_results";
360	} // namespace
361	
362	//===----------------------------------------------------------------------===//
363	// Main record log parser and decoder class
364	//===----------------------------------------------------------------------===//
365	
366	/// Simple decoder for translating QIR recorded results to a C++ binary data
367	/// structure.
368	class RecordLogParser {
369	public:
370	  RecordLogParser() = default;
371	  RecordLogParser(
372	      const std::pair<std::size_t, std::vector<std::size_t>> &layoutInfo)
373	      : dataLayoutInfo(layoutInfo) {}
374	  ~RecordLogParser() = default;
375	
376	  /// Does the heavy-lifting of parsing the output log and converting it to a
377	  /// binary data structure that is compatible with the C++ host code. The data
378	  /// structure is created in a generic memory buffer. The buffer's address and
379	  /// length may be queried and returned as a result.
380	  void parse(const std::string &outputLog);
381	
382	  /// Get a pointer to the data buffer. Note that the data buffer will be
383	  /// deallocated as soon as the RecordLogParser object is deconstructed.
384	  void *getBufferPtr() const { return bufferHandler.getBufferPtr(); }
385	
386	  /// Get the size of the data buffer (in bytes).
387	  std::size_t getBufferSize() const { return bufferHandler.getBufferSize(); }
388	
389	private:
390	  /// Result-buffer storage for aggregate roots. FLAT appends element bytes;
391	  /// PREALLOCATED reserves the host layout before indexed insertion. This is
392	  /// separate from `RecordSchemaType` for implicit `RESULT` arrays which are
393	  /// materialized as a pre-allocated `vector<bool>` even when no labeled schema
394	  /// was declared.
395	  enum struct ContainerStorage { FLAT, PREALLOCATED };
396	
397	  /// Process different types of records
398	  void handleHeader(const std::vector<std::string> &,
399	                    std::optional<RecordSchemaType> &);
400	  void handleMetadata(const std::vector<std::string> &);
401	  /// Central dispatcher that handles different output types including scalar
402	  /// values, arrays, and tuples.
403	  void handleOutput(const std::vector<std::string> &);
404	  /// Allocate inner buffer for array records - one per shot
405	  void preallocateArray();
406	  /// Allocate contiguous memory for tuple records - one per shot
407	  void preallocateTuple();
408	  /// Process scalar values and non-labeled array/tuple entries
409	  void processSingleRecord(const std::string &, const std::string &);
410	  /// Extract index from label (out-of-order allowed), convert value to
411	  /// appropriate type and store in the pre-allocated buffer
412	  void processArrayEntry(const std::string &, const std::string &);
413	  void processTupleEntry(const std::string &, const std::string &);
414	  /// Require every root result in a log to use one container shape.
415	  void validateRootContainer(ContainerType);
416	  /// Require every aggregate root to use one storage representation.
417	  void validateRootContainer(ContainerType, ContainerStorage);
418	  /// Get data handler for the specified type
419	  detail::DataHandlerBase &getDataHandler(const std::string &dataType);
420	
421	  RecordSchemaType schema = RecordSchemaType::ORDERED;
422	  OutputType currentOutput;
423	  std::optional<ContainerType> rootContainerType;
424	  std::optional<ContainerStorage> rootContainerStorage;
425	  /// Manages the underlying buffer storage
426	  detail::BufferHandler bufferHandler;
427	  /// Tracks container metadata during decoding
428	  detail::ContainerMetadata containerMeta;
429	  /// Data layout information
430	  std::pair<std::optional<std::size_t>, std::vector<std::size_t>>
431	      dataLayoutInfo = {std::nullopt, {}};
432	  /// Metadata information extracted from the log
433	  std::unordered_map<std::string, std::string> metadata = {
434	      {ResultCountMetadataName, "1"}};
435	};
436	} // namespace cudaq
