195	void cudaq::opt::initializeTypeConversions(LLVMTypeConverter &typeConverter) {
196	  typeConverter.addConversion([](cudaq::quake::VeqType type) {
197	    return cg::getLLVMArrayType(type.getContext());
198	  });
199	  typeConverter.addConversion([](cudaq::quake::RefType type) {
200	    return cg::getLLVMQubitType(type.getContext());
201	  });
202	  typeConverter.addConversion([&](cudaq::quake::StruqType type) {
203	    SmallVector<Type> mems;
204	    for (auto m : type.getMembers())
205	      mems.push_back(typeConverter.convertType(m));
206	    return LLVM::LLVMStructType::getLiteral(type.getContext(), mems,
207	                                            /*packed=*/false);
208	  });
209	  typeConverter.addConversion([](cudaq::quake::MeasureType type) {
210	    return IntegerType::get(type.getContext(), 1);
211	  });
212	  cudaq::opt::populateCCTypeConversions(&typeConverter);
213	}
