95	/// Lower quake dialect to cc dialect by calling support functions.
96	/// The strategy is to convert quake references and quake veqs to a uniform span
97	/// representation, where the former is a span of size 1 and the latter may be a
98	/// span of non-constant size.
99	/// All support functions will be declared as intrinsics. Some will be
100	/// implemented in C++ and others in the intrinsics table.
101	class AllocaOpRewrite : public OpConversionPattern<cudaq::quake::AllocaOp> {
102	public:
103	  using OpConversionPattern::OpConversionPattern;
104	
105	  LogicalResult
106	  matchAndRewrite(cudaq::quake::AllocaOp alloca, OpAdaptor adaptor,
107	                  ConversionPatternRewriter &rewriter) const override {
108	    auto loc = alloca.getLoc();
109	    auto i64Ty = rewriter.getI64Type();
110	    auto qspanTy = cudaq::opt::getCudaqQubitSpanType(rewriter.getContext());
111	    Value qspan = cudaq::cc::AllocaOp::create(rewriter, loc, qspanTy);
112	    if (auto resultType = dyn_cast<cudaq::quake::RefType>(alloca.getType())) {
113	      auto one = arith::ConstantIntOp::create(rewriter, loc, 1, 64);
114	      Value buffer = cudaq::cc::AllocaOp::create(rewriter, loc, i64Ty, one);
115	      auto call = func::CallOp::create(
116	          rewriter, loc, i64Ty, cudaq::opt::CudaqEMAllocate, ValueRange{});
117	      auto ptrI64Ty = cudaq::cc::PointerType::get(i64Ty);
118	      auto toAddr = cudaq::cc::ComputePtrOp::create(
119	          rewriter, loc, ptrI64Ty, buffer,
120	          ArrayRef<cudaq::cc::ComputePtrArg>{0});
121	      cudaq::cc::StoreOp::create(rewriter, loc, call.getResult(0), toAddr);
122	      func::CallOp::create(rewriter, loc, mlir::TypeRange{},
123	                           cudaq::opt::CudaqEMWriteToSpan,
124	                           ValueRange{qspan, buffer, one});
125	    } else {
126	      Value sizeOperand;
127	      if (adaptor.getOperands().empty()) {
128	        auto type = cast<cudaq::quake::VeqType>(alloca.getType());
129	        assert(type.hasSpecifiedSize() && "veq must have a constant size");
130	        auto constantSize = type.getSize();
131	        sizeOperand =
132	            arith::ConstantIntOp::create(rewriter, loc, constantSize, 64);
133	      } else if (auto intSizeTy =
134	                     dyn_cast<IntegerType>(adaptor.getSize().getType())) {
135	        sizeOperand = adaptor.getSize();
136	        if (intSizeTy.getWidth() != 64)
137	          sizeOperand =
138	              cudaq::cc::CastOp::create(rewriter, loc, i64Ty, sizeOperand,
139	                                        cudaq::cc::CastOpMode::Unsigned);
140	      }
141	      if (!sizeOperand)
142	        return failure();
143	
144	      Value buffer =
145	          cudaq::cc::AllocaOp::create(rewriter, loc, i64Ty, sizeOperand);
146	      func::CallOp::create(rewriter, loc, mlir::TypeRange{},
147	                           cudaq::opt::CudaqEMWriteToSpan,
148	                           ValueRange{qspan, buffer, sizeOperand});
149	      func::CallOp::create(rewriter, loc, mlir::TypeRange{},
150	                           cudaq::opt::CudaqEMAllocateVeq,
151	                           ValueRange{qspan, sizeOperand});
152	    }
153	    rewriter.replaceOp(alloca, qspan);
154	    return success();
155	  }
156	};
