306	template <typename OP>
307	class GenericRewrite : public OpConversionPattern<OP> {
308	public:
309	  using Base = OpConversionPattern<OP>;
310	  using Base::Base;
311	
312	  LogicalResult
313	  matchAndRewrite(OP qop, typename Base::OpAdaptor adaptor,
314	                  ConversionPatternRewriter &rewriter) const override {
315	    auto loc = qop.getLoc();
316	    auto instName = qop->getName().stripDialect().str();
317	    auto mod = qop->template getParentOfType<ModuleOp>();
318	    auto opName = createOpName(loc, mod, rewriter, instName);
319	    auto i8Ty = rewriter.getI8Type();
320	    auto ptrI8Ty = cudaq::cc::PointerType::get(i8Ty);
321	    auto regTy = cudaq::cc::PointerType::get(opName.getType());
322	    auto addr = cudaq::cc::AddressOfOp::create(rewriter, loc, regTy,
323	                                               opName.getSymName());
324	    auto opString = cudaq::cc::CastOp::create(rewriter, loc, ptrI8Ty, addr);
325	    auto paramSize = adaptor.getParameters().size();
326	    Value numParams =
327	        arith::ConstantIntOp::create(rewriter, loc, paramSize, 64);
328	    auto f64Ty = rewriter.getF64Type();
329	    auto arrF64Ty = cudaq::cc::ArrayType::get(f64Ty);
330	    auto ptrParamTy = cudaq::cc::PointerType::get(arrF64Ty);
331	    auto ptrF64Ty = cudaq::cc::PointerType::get(f64Ty);
332	    auto params = [&]() -> Value {
333	      if (paramSize == 0) {
334	        auto zero = arith::ConstantIntOp::create(rewriter, loc, paramSize, 64);
335	        return cudaq::cc::CastOp::create(rewriter, loc, ptrParamTy, zero);
336	      }
337	      auto buffer =
338	          cudaq::cc::AllocaOp::create(rewriter, loc, f64Ty, numParams);
339	      for (auto iter : llvm::enumerate(adaptor.getParameters())) {
340	        std::int32_t i = iter.index();
341	        auto p = iter.value();
342	        auto ptr = cudaq::cc::ComputePtrOp::create(
343	            rewriter, loc, ptrF64Ty, buffer,
344	            ArrayRef<cudaq::cc::ComputePtrArg>{i});
345	        cudaq::cc::StoreOp::create(rewriter, loc, p, ptr);
346	      }
347	      return buffer;
348	    }();
349	    auto controls = packQubitSpans(loc, rewriter, adaptor.getControls());
350	    auto targets = packQubitSpans(loc, rewriter, adaptor.getTargets());
351	    auto isAdj = [&]() -> Value {
352	      if (qop.isAdj())
353	        return arith::ConstantIntOp::create(rewriter, loc, 1, 1);
354	      return arith::ConstantIntOp::create(rewriter, loc, 0, 1);
355	    }();
356	    rewriter.template replaceOpWithNewOp<func::CallOp>(
357	        qop, mlir::TypeRange{}, cudaq::opt::CudaqEMApply,
358	        ValueRange{opString, numParams, params, controls, targets, isAdj});
359	    return success();
360	  }
361	
362	  // Create a global with the "name" to use for this operation.
363	  LLVM::GlobalOp createOpName(Location loc, ModuleOp mod,
364	                              ConversionPatternRewriter &rewriter,
365	                              StringRef name) const {
366	    OpBuilder::InsertionGuard guard(rewriter);
367	    auto builder = cudaq::IRBuilder::atBlockEnd(mod.getBody());
368	    return builder.genCStringLiteralAppendNul(loc, mod, name.str());
369	  }
370	};
