372	class MzOpRewrite : public OpConversionPattern<cudaq::quake::MzOp> {
373	public:
374	  using OpConversionPattern::OpConversionPattern;
375	
376	  // Create a global with the "name" to use for this measurement.
377	  LLVM::GlobalOp createRegisterName(Location loc, ModuleOp mod,
378	                                    ConversionPatternRewriter &rewriter,
379	                                    StringAttr nameAttr) const {
380	    std::string mzName;
381	    if (nameAttr) {
382	      mzName = nameAttr.getValue().str();
383	    } else {
384	      // No name was given. Use a hash based on the source file location of the
385	      // measurement operation, to give something that ought to be relatively
386	      // unique.
387	      std::size_t hash = mlir::hash_value(loc);
388	      hash = (hash ^ (hash >> 16)) & 0xFFFF;
389	      mzName = std::string("r") + std::to_string(hash);
390	    }
391	    OpBuilder::InsertionGuard guard(rewriter);
392	    auto builder = cudaq::IRBuilder::atBlockEnd(mod.getBody());
393	    return builder.genCStringLiteralAppendNul(loc, mod, mzName);
394	  }
395	
396	  LogicalResult
397	  matchAndRewrite(cudaq::quake::MzOp mzOp, OpAdaptor adaptor,
398	                  ConversionPatternRewriter &rewriter) const override {
399	    auto loc = mzOp.getLoc();
400	    auto mod = mzOp->getParentOfType<ModuleOp>();
401	    auto regName =
402	        createRegisterName(loc, mod, rewriter, mzOp.getRegisterNameAttr());
403	    auto i8Ty = rewriter.getI8Type();
404	    auto ptrI8Ty = cudaq::cc::PointerType::get(i8Ty);
405	    auto regTy = cudaq::cc::PointerType::get(regName.getType());
406	    auto addr = cudaq::cc::AddressOfOp::create(rewriter, loc, regTy,
407	                                               regName.getSymName());
408	    auto nameAddr = cudaq::cc::CastOp::create(rewriter, loc, ptrI8Ty, addr);
409	    auto i32Ty = rewriter.getI32Type();
410	    rewriter.replaceOpWithNewOp<func::CallOp>(
411	        mzOp, i32Ty, cudaq::opt::CudaqEMMeasure,
412	        ValueRange{adaptor.getTargets()[0], nameAddr});
413	    return success();
414	  }
415	};
