417	/// Convert a MX operation to a sequence H; MZ.
418	class MxToMzRewrite : public OpRewritePattern<cudaq::quake::MxOp> {
419	public:
420	  using OpRewritePattern::OpRewritePattern;
421	
422	  LogicalResult matchAndRewrite(cudaq::quake::MxOp mx,
423	                                PatternRewriter &rewriter) const override {
424	    cudaq::quake::HOp::create(rewriter, mx.getLoc(), mx.getTargets());
425	    rewriter.replaceOpWithNewOp<cudaq::quake::MzOp>(
426	        mx, mx.getResultTypes(), mx.getTargets(), mx.getRegisterNameAttr());
427	    return success();
428	  }
429	};
430	
431	/// Convert a MY operation to a sequence S; H; MZ.
432	class MyToMzRewrite : public OpRewritePattern<cudaq::quake::MyOp> {
433	public:
434	  using OpRewritePattern::OpRewritePattern;
435	
436	  LogicalResult matchAndRewrite(cudaq::quake::MyOp my,
437	                                PatternRewriter &rewriter) const override {
438	    cudaq::quake::SOp::create(rewriter, my.getLoc(), true, ValueRange{},
439	                              ValueRange{}, my.getTargets());
440	    cudaq::quake::HOp::create(rewriter, my.getLoc(), my.getTargets());
441	    rewriter.replaceOpWithNewOp<cudaq::quake::MzOp>(
442	        my, my.getResultTypes(), my.getTargets(), my.getRegisterNameAttr());
443	    return success();
444	  }
445	};
446	
447	class VeqSizeOpRewrite : public OpConversionPattern<cudaq::quake::VeqSizeOp> {
448	public:
449	  using OpConversionPattern::OpConversionPattern;
450	
451	  LogicalResult
452	  matchAndRewrite(cudaq::quake::VeqSizeOp vecsize, OpAdaptor adaptor,
453	                  ConversionPatternRewriter &rewriter) const override {
454	    auto loc = vecsize->getLoc();
455	    auto i64Ty = rewriter.getI64Type();
456	    auto ptrI64Ty = cudaq::cc::PointerType::get(i64Ty);
457	    auto sizeptr = cudaq::cc::ComputePtrOp::create(
458	        rewriter, loc, ptrI64Ty, adaptor.getVeq(),
459	        ArrayRef<cudaq::cc::ComputePtrArg>{1});
460	    rewriter.replaceOpWithNewOp<cudaq::cc::LoadOp>(vecsize, sizeptr);
461	    return success();
462	  }
463	};
464	
465	} // namespace
466	
467	void cudaq::opt::populateQuakeToCCPatterns(TypeConverter &converter,
468	                                           RewritePatternSet &patterns) {
469	  auto *context = patterns.getContext();
470	  patterns.insert<
471	      AllocaOpRewrite, ConcatOpRewrite, DeallocOpRewrite, DiscriminateOpRewrite,
472	      ExtractRefOpRewrite, VeqSizeOpRewrite, MzOpRewrite, ResetRewrite,
473	      SubveqOpRewrite, GenericRewrite<cudaq::quake::HOp>,
474	      GenericRewrite<cudaq::quake::PhasedRxOp>,
475	      GenericRewrite<cudaq::quake::R1Op>, GenericRewrite<cudaq::quake::RxOp>,
476	      GenericRewrite<cudaq::quake::RyOp>, GenericRewrite<cudaq::quake::RzOp>,
477	      GenericRewrite<cudaq::quake::SOp>, GenericRewrite<cudaq::quake::SwapOp>,
478	      GenericRewrite<cudaq::quake::TOp>, GenericRewrite<cudaq::quake::U2Op>,
479	      GenericRewrite<cudaq::quake::U3Op>, GenericRewrite<cudaq::quake::XOp>,
480	      GenericRewrite<cudaq::quake::YOp>, GenericRewrite<cudaq::quake::ZOp>>(
481	      converter, context);
482	}
