129	void cudaq::RecordLogParser::handleHeader(
130	    const std::vector<std::string> &entries,
131	    std::optional<RecordSchemaType> &declaredSchema) {
132	  if (entries.size() != 3)
133	    throw std::runtime_error("Invalid HEADER record");
134	  if (entries[1] == "schema_id") {
135	    RecordSchemaType parsedSchema;
136	    if (entries[2] == "labeled")
137	      parsedSchema = RecordSchemaType::LABELED;
138	    else if (entries[2] == "ordered")
139	      parsedSchema = RecordSchemaType::ORDERED;
140	    else
141	      throw std::runtime_error("Unknown schema type");
142	    if (declaredSchema.has_value() && declaredSchema != parsedSchema)
143	      throw std::runtime_error("Conflicting schema declarations");
144	    declaredSchema = parsedSchema;
145	    schema = parsedSchema;
146	  }
147	  /// TODO: Handle schema version if needed
148	}
