150	void cudaq::RecordLogParser::handleMetadata(
151	    const std::vector<std::string> &entries) {
152	  if (entries.size() < 2 || entries.size() > 3)
153	    throw std::runtime_error("Invalid METADATA record");
154	  if (entries.size() == 3) {
155	    if (entries[1] == cudaq::opt::qir1_0::RequiredResultsAttrName ||
156	        entries[1] == cudaq::opt::qir0_1::RequiredResultsAttrName) {
157	      detail::parseSize(entries[2]);
158	      metadata[ResultCountMetadataName] = entries[2];
159	    } else {
160	      metadata[entries[1]] = entries[2];
161	    }
162	  } else {
163	    metadata[entries[1]] = "";
164	  }
165	}
166	
167	void cudaq::RecordLogParser::handleOutput(
168	    const std::vector<std::string> &entries) {
169	  const std::string &recType = entries[1];
170	  const std::string &recValue = entries[2];
171	  std::string recLabel = (entries.size() == 4) ? entries[3] : "";
172	  cudaq::trim(recLabel);
173	  if (recType == "RESULT") {
174	    // Sample-type QIR output, where we have an array of `RESULT` per shot. For
175	    // example,
176	    //  START
177	    //  OUTPUT    RESULT  1       r00000
178	    //  ....
179	    //  OUTPUT    RESULT  1       r00009
180	    //  END       0
181	
182	    currentOutput = OutputType::RESULT;
183	    const bool isUninitializedContainer =
184	        (containerMeta.m_type == ContainerType::NONE) ||
185	        (containerMeta.m_type == ContainerType::ARRAY &&
186	         containerMeta.elementCount == 0);
187	    if (isUninitializedContainer) {
188	      validateRootContainer(ContainerType::ARRAY,
189	                            ContainerStorage::PREALLOCATED);
190	      // NOTE: This is a temporary workaround until all backends consistently
191	      // use the new transformation pass that wraps result records inside an
192	      // array record output. For now, we permit "naked" RESULT records, i.e.,
193	      // if the QIR produced by a sampled kernel emits a sequence of RESULT
194	      // records without enclosing them in an ARRAY, we interpret them
195	      // collectively as an array of results.
196	      // NOTE: This assumption prevents us from correctly supporting `run` with
197	      // `qir-base` profile.
198	      containerMeta.m_type = ContainerType::ARRAY;
199	      containerMeta.elementCount =
200	          detail::parseSize(metadata[ResultCountMetadataName]);
201	      containerMeta.arrayType = "i1";
202	      preallocateArray();
203	    }
204	
205	    // Note: For ordered schema, we expect the results are sequential in the
206	    // same order that mz operations are called. This may include results in
207	    // named registers (specified in kernel code) and other auto-generated
208	    // register names. If index cannot be extracted from the label, we fall back
209	    // to using this mechanism.
210	    auto idxLabel = std::to_string(containerMeta.processedElements);
211	
212	    // Get the index from the label, if feasible.
213	    /// TODO: The `sample` API should be updated to not allow explicit
214	    /// measurement operations in the kernel when targeting hardware backends.
215	    // Until then, we handle both cases here - auto-generated labels like
216	    // r00000, r00001, ... and named results like result%0, result%1, ...
217	    if (!recLabel.empty()) {
218	      std::size_t percentPos = recLabel.find('%');
219	      if (percentPos != std::string::npos) {
220	        idxLabel = recLabel.substr(percentPos + 1);
221	      }
222	      // This logic is fragile; for example user may have only one mz assigned
223	      // to variable like r00001 and it will be interpreted as index 1, and
224	      // cause `Array index out of bounds` error. The proper fix is to disallow
225	      // explicit mz operations in sampled kernels. Also, `run` is appropriate
226	      // for getting sub-register results.
227	      else if (recLabel.size() == 6 && recLabel[0] == 'r') {
228	        // check that the last 5 characters are all digits
229	        bool allDigits = true;
230	        for (std::size_t i = 1; i < 6; ++i) {
231	          if (recLabel[i] < '0' || recLabel[i] > '9') {
232	            allDigits = false;
233	            break;
234	          }
235	        }
236	        if (allDigits) {
237	          idxLabel = recLabel.substr(1);
238	        }
239	      }
240	    }
241	
242	    processArrayEntry(recValue, fmt::format("[{}]", idxLabel));
243	    containerMeta.processedElements++;
244	    return;
245	  }
246	  if (recType == "ARRAY") {
247	    validateRootContainer(ContainerType::ARRAY,
248	                          recLabel.empty() ? ContainerStorage::FLAT
249	                                           : ContainerStorage::PREALLOCATED);
250	    containerMeta.m_type = ContainerType::ARRAY;
251	    containerMeta.elementCount = detail::parseSize(recValue);
252	    if (!recLabel.empty()) {
253	      schema = RecordSchemaType::LABELED;
254	      containerMeta.extractArrayInfo(recLabel);
255	      preallocateArray();
256	    }
257	    return;
258	  }
259	  if (recType == "TUPLE") {
260	    validateRootContainer(ContainerType::TUPLE,
261	                          recLabel.empty() ? ContainerStorage::FLAT
262	                                           : ContainerStorage::PREALLOCATED);
263	    containerMeta.m_type = ContainerType::TUPLE;
264	    containerMeta.elementCount = detail::parseSize(recValue);
265	    if (!recLabel.empty()) {
266	      schema = RecordSchemaType::LABELED;
267	      containerMeta.extractTupleInfo(recLabel);
268	      preallocateTuple();
269	    }
270	    return;
271	  }
272	  if (recType == "BOOL")
273	    currentOutput = OutputType::BOOL;
274	  else if (recType == "INT")
275	    currentOutput = OutputType::INT;
276	  else if (recType == "DOUBLE")
277	    currentOutput = OutputType::DOUBLE;
278	  else if (recType == "RESULT")
279	    currentOutput = OutputType::RESULT;
280	  else
281	    throw std::runtime_error("Invalid data");
282	  if ((containerMeta.elementCount > 0) &&
283	      (schema == RecordSchemaType::LABELED)) {
284	    if (containerMeta.m_type == ContainerType::ARRAY)
285	      processArrayEntry(recValue, recLabel);
286	    else if (containerMeta.m_type == ContainerType::TUPLE)
287	      processTupleEntry(recValue, recLabel);
288	    containerMeta.processedElements++;
289	    if (containerMeta.processedElements == containerMeta.elementCount) {
290	      containerMeta.reset();
291	    }
292	  } else {
293	    if (containerMeta.elementCount == 0)
294	      validateRootContainer(ContainerType::NONE);
295	    processSingleRecord(recValue, recLabel);
296	  }
297	}
298	
