323	      std::make_unique<detail::IntegerConverter<std::int16_t>>());
324	  static detail::DataHandler<std::int32_t> i32Handler(
325	      std::make_unique<detail::IntegerConverter<std::int32_t>>());
326	  static detail::DataHandler<std::int64_t> i64Handler(
327	      std::make_unique<detail::IntegerConverter<std::int64_t>>());
328	  static detail::DataHandler<float> f32Handler(
329	      std::make_unique<detail::FloatConverter<float>>());
330	  static detail::DataHandler<double> f64Handler(
331	      std::make_unique<detail::FloatConverter<double>>());
332	  // Map data type to the corresponding handler
333	  if (dataType == "i1")
334	    return boolHandler;
335	  else if (dataType == "i8")
336	    return i8Handler;
337	  else if (dataType == "i16")
338	    return i16Handler;
339	  else if (dataType == "i32")
340	    return i32Handler;
341	  else if (dataType == "i64")
342	    return i64Handler;
343	  else if (dataType == "f32")
344	    return f32Handler;
345	  else if (dataType == "f64")
346	    return f64Handler;
347	  throw std::runtime_error("Unsupported data type: " + dataType);
348	}
