350	void cudaq::RecordLogParser::preallocateArray() {
351	  cudaq::detail::DataHandlerBase &dh = getDataHandler(containerMeta.arrayType);
352	  containerMeta.dataOffset =
353	      dh.allocateArray(bufferHandler, containerMeta.elementCount);
354	}
