356	void cudaq::RecordLogParser::preallocateTuple() {
357	  if (!dataLayoutInfo.first.has_value())
358	    throw std::runtime_error(
359	        "Data layout information missing for the struct / tuple type.");
360	  if (dataLayoutInfo.second.size() != containerMeta.tupleTypes.size())
361	    throw std::runtime_error("Tuple size mismatch in kernel and label.");
362	  const std::size_t tupleSize = dataLayoutInfo.first.value();
363	  for (std::size_t i = 0; i < dataLayoutInfo.second.size(); ++i) {
364	    const std::size_t offset = dataLayoutInfo.second[i];
365	    const std::size_t end = i + 1 < dataLayoutInfo.second.size()
366	                                ? dataLayoutInfo.second[i + 1]
367	                                : tupleSize;
368	    if (offset >= tupleSize || end <= offset || end > tupleSize)
369	      throw std::runtime_error("Invalid tuple layout");
370	    if (getTypeByteSize(containerMeta.tupleTypes[i]) > end - offset)
371	      throw std::runtime_error("Tuple element exceeds its layout slot");
372	  }
373	  containerMeta.dataOffset = bufferHandler.getBufferSize();
374	  // Directly allocate memory for the tuple, update offsets
375	  bufferHandler.resizeBuffer(tupleSize);
376	  containerMeta.tupleOffsets = dataLayoutInfo.second;
377	}
