379	void cudaq::RecordLogParser::processSingleRecord(const std::string &recValue,
380	                                                 const std::string &recLabel) {
381	  auto label = recLabel;
382	  // For result type, we don't use the record label (register name) as the type
383	  // annotation.
384	  if (currentOutput == OutputType::RESULT)
385	    label = "i1";
386	  if (label.empty()) {
387	    if (currentOutput == OutputType::BOOL)
388	      label = "i1";
389	    else if (currentOutput == OutputType::INT)
390	      label = "i32";
391	    else if (currentOutput == OutputType::DOUBLE)
392	      label = "f64";
393	  }
394	  cudaq::detail::DataHandlerBase &dh = getDataHandler(label);
395	  dh.addRecord(bufferHandler, recValue);
396	}
