398	void cudaq::RecordLogParser::processArrayEntry(const std::string &recValue,
399	                                               const std::string &recLabel) {
400	  std::size_t index = containerMeta.extractIndex(recLabel);
401	  if (index >= containerMeta.elementCount)
402	    throw std::runtime_error("Array index out of bounds");
403	  cudaq::detail::DataHandlerBase &dh = getDataHandler(containerMeta.arrayType);
404	  dh.insertIntoArray(bufferHandler, containerMeta.dataOffset, index, recValue);
405	}
