407	void cudaq::RecordLogParser::processTupleEntry(const std::string &recValue,
408	                                               const std::string &recLabel) {
409	  std::size_t index = containerMeta.extractIndex(recLabel);
410	  if (index >= containerMeta.elementCount)
411	    throw std::runtime_error("Tuple index out of bounds");
412	  cudaq::detail::DataHandlerBase &dh =
413	      getDataHandler(containerMeta.tupleTypes[index]);
414	  dh.insertIntoTuple(
415	      bufferHandler,
416	      containerMeta.dataOffset + containerMeta.tupleOffsets[index], recValue);
