19	namespace cudaq::opt {
20	#define GEN_PASS_DEF_RETURNTOOUTPUTLOG
21	#include "cudaq/Optimizer/CodeGen/Passes.h.inc"
22	} // namespace cudaq::opt
23	
24	#define DEBUG_TYPE "return-to-output-log"
25	
26	using namespace mlir;
27	
28	namespace {
29	class ReturnRewrite : public OpRewritePattern<cudaq::cc::LogOutputOp> {
30	public:
31	  ReturnRewrite(MLIRContext *ctx, bool allowDynamic)
32	      : OpRewritePattern(ctx), allowDynamic(allowDynamic) {}
33	
34	  // This is where the heavy lifting is done. We take the return op's operand(s)
35	  // and convert them to calls to the QIR output logging functions with the
36	  // appropriate label information.
37	  LogicalResult matchAndRewrite(cudaq::cc::LogOutputOp log,
38	                                PatternRewriter &rewriter) const override {
39	    auto loc = log.getLoc();
40	    // For each operand, generate a QIR logging call.
41	    for (auto operand : log.getOperands())
42	      genOutputLog(loc, rewriter, operand, std::nullopt, allowDynamic);
43	    rewriter.eraseOp(log);
44	    return success();
45	  }
46	
47	  static void genOutputLog(Location loc, PatternRewriter &rewriter, Value val,
48	                           std::optional<StringRef> prefix,
49	                           bool allowDynamic = false) {
50	    Type valTy = val.getType();
51	    TypeSwitch<Type>(valTy)
52	        .Case([&](IntegerType intTy) {
53	          int width = intTy.getWidth();
54	          std::string labelStr = std::string("i") + std::to_string(width);
55	          if (prefix)
56	            labelStr = prefix->str();
57	          Value label = makeLabel(loc, rewriter, labelStr);
58	          if (intTy.getWidth() == 1) {
59	            func::CallOp::create(rewriter, loc, TypeRange{},
60	                                 cudaq::opt::QIRBoolRecordOutput,
61	                                 ArrayRef<Value>{val, label});
62	            return;
63	          }
64	          // Integer: convert to (signed) i64. The decoder *must* lop off any
65	          // higher-order bits added by the sign-extension to get this to 64
66	          // bits by examining the real integer type.
67	          Value castVal = val;
68	          if (intTy.getWidth() < 64)
69	            castVal =
70	                cudaq::cc::CastOp::create(rewriter, loc, rewriter.getI64Type(),
71	                                          val, cudaq::cc::CastOpMode::Signed);
72	          else if (intTy.getWidth() > 64)
73	            castVal = cudaq::cc::CastOp::create(rewriter, loc,
74	                                                rewriter.getI64Type(), val);
75	          func::CallOp::create(rewriter, loc, TypeRange{},
76	                               cudaq::opt::QIRIntegerRecordOutput,
77	                               ArrayRef<Value>{castVal, label});
78	        })
79	        .Case([&](FloatType floatTy) {
80	          int width = floatTy.getWidth();
81	          std::string labelStr = std::string("f") + std::to_string(width);
82	          if (prefix)
83	            labelStr = prefix->str();
84	          Value label = makeLabel(loc, rewriter, labelStr);
85	          // Floating point: convert it to double, whatever it actually is.
86	          Value castVal = val;
87	          if (floatTy != rewriter.getF64Type())
88	            castVal = cudaq::cc::CastOp::create(rewriter, loc,
89	                                                rewriter.getF64Type(), val);
90	          func::CallOp::create(rewriter, loc, TypeRange{},
91	                               cudaq::opt::QIRDoubleRecordOutput,
92	                               ArrayRef<Value>{castVal, label});
93	        })
94	        .Case([&](cudaq::cc::StructType structTy) {
95	          auto labelStr = translateType(structTy);
96	          if (prefix)
97	            labelStr = prefix->str();
98	          Value label = makeLabel(loc, rewriter, labelStr);
99	          std::int32_t sz = structTy.getNumMembers();
100	          Value size = arith::ConstantIntOp::create(rewriter, loc, sz, 64);
101	          func::CallOp::create(rewriter, loc, TypeRange{},
102	                               cudaq::opt::QIRTupleRecordOutput,
103	                               ArrayRef<Value>{size, label});
104	          std::string preStr = prefix ? prefix->str() : std::string{};
105	          for (std::int32_t i = 0; i < sz; ++i) {
106	            std::string offset = preStr + std::string(".") + std::to_string(i);
107	            Value w = cudaq::cc::ExtractValueOp::create(
108	                rewriter, loc, structTy.getMember(i), val,
109	                ArrayRef<cudaq::cc::ExtractValueArg>{i});
110	            genOutputLog(loc, rewriter, w, offset, allowDynamic);
111	          }
112	        })
113	        .Case([&](cudaq::cc::ArrayType arrTy) {
114	          auto labelStr = translateType(arrTy);
115	          Value label = makeLabel(loc, rewriter, labelStr);
116	          std::int32_t sz = arrTy.getSize();
117	          Value size = arith::ConstantIntOp::create(rewriter, loc, sz, 64);
118	          func::CallOp::create(rewriter, loc, TypeRange{},
119	                               cudaq::opt::QIRArrayRecordOutput,
120	                               ArrayRef<Value>{size, label});
121	          std::string preStr = prefix ? prefix->str() : std::string{};
122	          for (std::int32_t i = 0; i < sz; ++i) {
123	            std::string offset = preStr + std::string("[") + std::to_string(i) +
124	                                 std::string("]");
125	            Value w = cudaq::cc::ExtractValueOp::create(
126	                rewriter, loc, arrTy.getElementType(), val,
127	                ArrayRef<cudaq::cc::ExtractValueArg>{i});
128	            genOutputLog(loc, rewriter, w, offset, allowDynamic);
129	          }
130	        })
131	        .Case([&](cudaq::cc::StdvecType vecTy) {
132	          // For this type, we expect a cc.stdvec_init operation as the input.
133	          // The data will be in a variable.
134	          if (auto vecInit = val.getDefiningOp<cudaq::cc::StdvecInitOp>()) {
135	            auto maybeLen = [&]() -> std::optional<std::uint64_t> {
136	              if (Value len = vecInit.getLength())
137	                return cudaq::opt::factory::maybeValueOfIntConstant(len);
138	              auto eleTy =
139	                  cast<cudaq::cc::PointerType>(vecInit.getBuffer().getType())
140	                      .getElementType();
141	              if (auto arrTy = dyn_cast<cudaq::cc::ArrayType>(eleTy);
142	                  arrTy && !arrTy.isUnknownSize())
143	                return {arrTy.getSize()};
144	              return std::nullopt;
145	            }();
146	            if (maybeLen) {
147	              std::int64_t sz = *maybeLen;
148	              auto labelStr = translateType(vecTy, sz);
149	              Value label = makeLabel(loc, rewriter, labelStr);
150	              Value size = arith::ConstantIntOp::create(rewriter, loc, sz, 64);
151	              func::CallOp::create(rewriter, loc, TypeRange{},
152	                                   cudaq::opt::QIRArrayRecordOutput,
153	                                   ArrayRef<Value>{size, label});
154	              std::string preStr = prefix ? prefix->str() : std::string{};
155	              Value rawBuffer = vecInit.getBuffer();
156	              if (auto callOp = rawBuffer.getDefiningOp<func::CallOp>()) {
157	                if (callOp.getCallee() == "__nvqpp_vectorCopyCtor" &&
158	                    callOp.getNumOperands() >= 1) {
159	                  rawBuffer = callOp.getOperand(0);
160	                } else if (callOp.getCallee() == "malloc") {
161	                  for (auto *user : rawBuffer.getUsers()) {
162	                    auto memcpy = dyn_cast<func::CallOp>(user);
163	                    if (memcpy &&
164	                        memcpy.getCallee().starts_with("llvm.memcpy") &&
165	                        memcpy.getNumOperands() >= 2 &&
166	                        memcpy.getOperand(0) == rawBuffer) {
167	                      rawBuffer = memcpy.getOperand(1);
168	                      break;
169	                    }
170	                  }
171	                }
172	              }
173	              auto eleTy = vecTy.getElementType();
174	              auto buffTy = cudaq::cc::PointerType::get(eleTy);
175	              auto ptrArrTy =
176	                  cudaq::cc::PointerType::get(cudaq::cc::ArrayType::get(eleTy));
177	              Value buffer =
178	                  cudaq::cc::CastOp::create(rewriter, loc, ptrArrTy, rawBuffer);
179	              for (std::int32_t i = 0; i < sz; ++i) {
180	                std::string offset = preStr + std::string("[") +
181	                                     std::to_string(i) + std::string("]");
182	                auto v = cudaq::cc::ComputePtrOp::create(
183	                    rewriter, loc, buffTy, buffer,
184	                    ArrayRef<cudaq::cc::ComputePtrArg>{i});
185	                Value w = cudaq::cc::LoadOp::create(rewriter, loc, v);
186	                genOutputLog(loc, rewriter, w, offset, allowDynamic);
187	              }
188	              return;
189	            }
190	          }
191	          // Dynamic size: use runtime span logging helpers.
192	          if (!allowDynamic)
193	            return;
194	          auto eleTy = vecTy.getElementType();
195	          auto i8PtrTy = cudaq::cc::PointerType::get(rewriter.getI8Type());
196	          Value size = cudaq::cc::StdvecSizeOp::create(
197	              rewriter, loc, rewriter.getI64Type(), val);
198	          Value rawData =
199	              cudaq::cc::StdvecDataOp::create(rewriter, loc, i8PtrTy, val);
200	          if (auto intTy = dyn_cast<IntegerType>(eleTy)) {
201	            if (eleTy == rewriter.getI1Type()) {
202	              func::CallOp::create(rewriter, loc, TypeRange{},
203	                                   cudaq::opt::QIRBoolSpanRecordOutput,
204	                                   ArrayRef<Value>{rawData, size});
205	            } else {
206	              std::int32_t byteSize =
207	                  cudaq::opt::convertBitsToBytes(intTy.getWidth());
208	              Value elemSize =
209	                  arith::ConstantIntOp::create(rewriter, loc, byteSize, 32);
210	              func::CallOp::create(rewriter, loc, TypeRange{},
211	                                   cudaq::opt::QIRIntSpanRecordOutput,
212	                                   ArrayRef<Value>{rawData, size, elemSize});
213	            }
214	          } else if (isa<FloatType>(eleTy)) {
215	            auto floatTy = cast<FloatType>(eleTy);
216	            std::int32_t byteSize = floatTy.getWidth() / 8;
217	            Value elemSize =
218	                arith::ConstantIntOp::create(rewriter, loc, byteSize, 32);
219	            func::CallOp::create(rewriter, loc, TypeRange{},
220	                                 cudaq::opt::QIRFloatSpanRecordOutput,
221	                                 ArrayRef<Value>{rawData, size, elemSize});
222	          } else {
223	            // Unsupported element type — trap.
224	            LLVM_DEBUG(llvm::dbgs()
225	                       << "ReturnToOutputLog -- unsupported element type: "
226	                       << eleTy << "\n");
227	            Value one = arith::ConstantIntOp::create(rewriter, loc, 1, 64);
228	            func::CallOp::create(rewriter, loc, TypeRange{},
229	                                 cudaq::opt::QISTrap, ValueRange{one});
230	          }
231	        })
232	        .Default([&](Type) {
233	          // If we reach here, we don't know how to handle this type.
234	          Value one = arith::ConstantIntOp::create(rewriter, loc, 1, 64);
235	          func::CallOp::create(rewriter, loc, TypeRange{}, cudaq::opt::QISTrap,
236	                               ValueRange{one});
237	        });
238	  }
239	
240	  static std::string
241	  translateType(Type ty, std::optional<std::int32_t> vecSz = std::nullopt) {
242	    if (auto intTy = dyn_cast<IntegerType>(ty)) {
243	      int width = intTy.getWidth();
244	      return {std::string("i") + std::to_string(width)};
245	    }
246	    if (auto floatTy = dyn_cast<FloatType>(ty)) {
247	      int width = floatTy.getWidth();
248	      return {std::string("f") + std::to_string(width)};
249	    }
250	    if (auto structTy = dyn_cast<cudaq::cc::StructType>(ty)) {
251	      std::string result = "tuple<";
252	      if (structTy.getMembers().empty())
253	        return {result + std::string(">")};
254	      result += translateType(structTy.getMembers().front());
255	      for (auto memTy : structTy.getMembers().drop_front())
256	        result += std::string(", ") + translateType(memTy);
257	      return {result + std::string(">")};
258	    }
259	    if (auto arrTy = dyn_cast<cudaq::cc::ArrayType>(ty)) {
260	      std::int32_t size = arrTy.getSize();
261	      return {std::string("array<") + translateType(arrTy.getElementType()) +
262	              std::string(" x ") + std::to_string(size) + std::string(">")};
263	    }
264	    if (auto arrTy = dyn_cast<cudaq::cc::StdvecType>(ty)) {
265	      if (!vecSz)
266	        return {"error"};
267	      return {std::string("array<") + translateType(arrTy.getElementType()) +
268	              std::string(" x ") + std::to_string(*vecSz) + std::string(">")};
269	    }
270	    return {"error"};
271	  }
272	
273	  static Value makeLabel(Location loc, PatternRewriter &rewriter,
274	                         StringRef label) {
275	    auto strLitTy = cudaq::cc::PointerType::get(cudaq::cc::ArrayType::get(
276	        rewriter.getContext(), rewriter.getI8Type(), label.size() + 1));
277	    Value lit = cudaq::cc::CreateStringLiteralOp::create(
278	        rewriter, loc, strLitTy, rewriter.getStringAttr(label));
279	    auto i8PtrTy = cudaq::cc::PointerType::get(rewriter.getI8Type());
280	    return cudaq::cc::CastOp::create(rewriter, loc, i8PtrTy, lit);
281	  }
282	
283	  bool allowDynamic;
284	};
285	
286	struct ReturnToOutputLogPass
287	    : public cudaq::opt::impl::ReturnToOutputLogBase<ReturnToOutputLogPass> {
288	  using ReturnToOutputLogBase::ReturnToOutputLogBase;
289	
290	  void runOnOperation() override {
291	    auto module = getOperation();
292	
293	    auto *ctx = &getContext();
294	    auto irBuilder = cudaq::IRBuilder::atBlockEnd(module.getBody());
295	    if (failed(irBuilder.loadIntrinsic(module,
296	                                       cudaq::opt::QIRArrayRecordOutput))) {
297	      module.emitError("could not load QIR output logging functions.");
298	      signalPassFailure();
299	      return;
300	    }
301	    if (failed(irBuilder.loadIntrinsic(module, cudaq::opt::QISTrap))) {
302	      module.emitError("could not load QIR trap function.");
303	      signalPassFailure();
304	      return;
305	    }
306	    if (allowDynamicResult) {
307	      if (failed(irBuilder.loadIntrinsic(
308	              module, cudaq::opt::QIRBoolSpanRecordOutput)) ||
309	          failed(irBuilder.loadIntrinsic(module,
310	                                         cudaq::opt::QIRIntSpanRecordOutput)) ||
311	          failed(irBuilder.loadIntrinsic(
312	              module, cudaq::opt::QIRFloatSpanRecordOutput))) {
313	        module.emitError("could not load QIR span output logging functions.");
314	        signalPassFailure();
315	        return;
316	      }
317	    }
318	
319	    RewritePatternSet patterns(ctx);
320	    patterns.insert<ReturnRewrite>(ctx, allowDynamicResult);
321	    LLVM_DEBUG(llvm::dbgs() << "Before return to output logging:\n" << module);
322	    if (failed(applyPatternsGreedily(module, std::move(patterns))))
323	      signalPassFailure();
324	    LLVM_DEBUG(llvm::dbgs() << "After return to output logging:\n" << module);
325	  }
326	};
327	
328	} // namespace
